  const files = r.filesChanged.slice(0, 5).join(", ");
  const more = r.filesChanged.length > 5 ? ` +${r.filesChanged.length - 5} more` : "";

  return [
    `${rank}. **${r.shortHash}** — ${date} — @${r.authorName}${mergeTag}`,
    `   ${r.message.split("\n")[0]}`,
    `   Files: ${files}${more} (+${r.insertions} -${r.deletions})`,
  ].join("\n");
}

